mapper.select:
select 

from sys_dic s
where s.DIC_TYPE = #{dicType,jdbcType=VARCHAR}

select , GET_REAL_NAME(s.`LAST_UPDATED_BY`) AS lastUpdateName
from sys_dic s where s.dic_id IN (SELECT MIN(t.dic_id) FROM sys_dic t GROUP BY t.DIC_TYPE)

    and  s.DIC_NAME like '%${dicName}%'


    and  s.DIC_TYPE like '%${dicType}%'


    order by ${sort} ${order}

select  
from sys_dic s where s.DIC_NAME=#{dicName} and s.DIC_TYPE=#{dicType}

    and  s.dic_key like '%${dicKey}%'


    and  s.DIC_VALUE like '%${dicValue}%'


    order by ${sort} ${order}

SELECT COUNT(1) NUM FROM SYS_DIC WHERE (DIC_NAME=#{dicName} or DIC_TYPE=#{dicType})
AND dic_id not in (select s.dic_id
from SYS_DIC s where s.DIC_TYPE = (select f.DIC_TYPE from SYS_DIC f where f.dic_id = #{dicId}) or s.DIC_NAME = (select f.DIC_NAME from SYS_DIC f where f.dic_id = #{dicId}) )

mapper.insert:
