    CREATED_DATE, LAST_UPDATED_BY, LAST_UPDATED_DATE,DIC_SYMBOL
    )
values ( #{dicName,jdbcType=VARCHAR}, #{dicType,jdbcType=VARCHAR},
    #{dicKey,jdbcType=VARCHAR}, #{dicValue,jdbcType=VARCHAR}, #{createdBy,jdbcType=INTEGER},
    #{createdDate,jdbcType=TIMESTAMP}, #{lastUpdatedBy,jdbcType=INTEGER}, #{lastUpdatedDate,jdbcType=TIMESTAMP},#{dicSymbol,jdbcType=VARCHAR}
